from openai_agents import Agent, tool
from vex_sdk import VexGuardrail

@tool
def process_payment(amount: float, user_id: str) -> dict:
    """Process payment with idempotency checks"""
    return {'status': 'success', 'idempotency_key': f'pay_{user_id}'}

api_agent = Agent(
    name="PaymentAPI",
    tools=[process_payment],
    guardrail=VexGuardrail(
        rules=[
            "permission: user_id in approved_users",
            "idempotent: idempotency_key exists",
            "amount_positive: amount > 0"
        ]
    )
)

