from vex_sdk import Vex

vex = Vex(api_key="your-vex-key")

def guarded_agent_response(agent, input):
    response = agent.run(input)

    # Vex validates before handoff
    validated = vex.guardrail.check({
        'action': response.action,
        'output': response.content,
        'context': {'workflow_step': agent.name}
    }, rules=[
        "action_correctness: action matches workflow_state",
        "no_injection: no_prompt_injection(response.content)",
        "schema_valid: response matches expected_schema"
    ])

    return validated.response if validated.safe else None

def safe_api_call(api_payload):
    result = vex.guardrail.check(api_payload, rules=[
        "permission_check: user_has_permission(api_payload.user_id, api_payload.action)",
        "idempotency: check_idempotency_key(api_payload.key)",
        "rollback_ready: transaction supports rollback"
    ])

    if result.safe:
        return make_api_call(api_payload)
    else:
        # Auto-rollback on failure
        rollback_transaction(api_payload)
        return {'error': 'Vex blocked unsafe action'}
